import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';

const Dashboard = () => {
    const [stats, setStats] = useState({
        totalCars: 0,
        totalUsers: 0,
        totalTestDrives: 0,
        pendingReviews: 0
    });
    const [recentTestDrives, setRecentTestDrives] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchDashboardData();
    }, []);

    const fetchDashboardData = async () => {
        try {
            // Lấy số liệu thống kê
            const [carsRes, usersRes, testDrivesRes, reviewsRes] = await Promise.all([
                axios.get('http://localhost:5000/api/cars'),
                axios.get('http://localhost:5000/api/admin/users'),
                axios.get('http://localhost:5000/api/admin/testdrives'),
                axios.get('http://localhost:5000/api/admin/reviews/pending')
            ]);

            setStats({
                totalCars: carsRes.data.length || 0,
                totalUsers: usersRes.data.length || 0,
                totalTestDrives: testDrivesRes.data.length || 0,
                pendingReviews: reviewsRes.data.length || 0
            });

            setRecentTestDrives(testDrivesRes.data.slice(0, 5));
            setLoading(false);
        } catch (error) {
            console.error('Lỗi tải dashboard:', error);
            setLoading(false);
        }
    };

    if (loading) return <div className="loading">Đang tải...</div>;

    return (
        <div>
            <h1>Dashboard</h1>
            
            <div className="dashboard-stats">
                <div className="stat-card">
                    <h3>🚗 Tổng số xe</h3>
                    <div className="stat-number">{stats.totalCars}</div>
                </div>
                
                <div className="stat-card">
                    <h3>👥 Người dùng</h3>
                    <div className="stat-number">{stats.totalUsers}</div>
                </div>
                
                <div className="stat-card">
                    <h3>📅 Lịch lái thử</h3>
                    <div className="stat-number">{stats.totalTestDrives}</div>
                </div>
                
                <div className="stat-card">
                    <h3>⏳ Đánh giá chờ</h3>
                    <div className="stat-number">{stats.pendingReviews}</div>
                </div>
            </div>

            <div style={{ marginTop: '30px' }}>
                <h2>Lịch lái thử gần đây</h2>
                <table className="admin-table">
                    <thead>
                        <tr>
                            <th>Người đặt</th>
                            <th>Xe</th>
                            <th>Ngày</th>
                            <th>Giờ</th>
                            <th>Trạng thái</th>
                            <th>Thao tác</th>
                        </tr>
                    </thead>
                    <tbody>
                        {recentTestDrives.map(drive => (
                            <tr key={drive.id}>
                                <td>{drive.fullname}</td>
                                <td>{drive.car_name}</td>
                                <td>{drive.test_date}</td>
                                <td>{drive.test_time}</td>
                                <td>
                                    <span className={`status-badge ${drive.status}`}>
                                        {drive.status}
                                    </span>
                                </td>
                                <td>
                                    <Link to={`/admin/testdrives/${drive.id}`} className="btn-view">
                                        Xem
                                    </Link>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    );
};

export default Dashboard;
